// Native microsoftSharePoint getAll returns items as array directly
// Each item has: id (list item ID) and the field values at top level
// (the node flattens fields for us — no .fields wrapper needed)
const raw = $input.item.json;
const items = Array.isArray(raw) ? raw : (raw.value || []);

return items.map(item => ({
  json: {
    listItemId: item.id,
    guestId: item.GuestId || item.fields?.GuestId,
    guestEmail: item.GuestEmail || item.fields?.GuestEmail || '',
    guestEmailODataSafe: (item.GuestEmail || item.fields?.GuestEmail || '').replace(/'/g, "''"),
    displayName: item.DisplayName || item.fields?.DisplayName,
    lastSignIn: item.LastSignIn || item.fields?.LastSignIn,
    sponsorEmail: item.SponsorEmail || item.fields?.SponsorEmail,
    sponsorName: item.SponsorName || item.fields?.SponsorName,
    scheduledDeletionTime: item.ScheduledDeletionTime || item.fields?.ScheduledDeletionTime
  }
}));

