// Built-in HTTP pagination means $input.item.json contains
// the LAST page response, but n8n has already accumulated all items
// via requestWithAuthenticationPaginated. The full guest array is in value[].
const response = $input.item.json;
const allUsers = response.value || [];
const cutoffDate = new Date($('Config').item.json.cutoffDate);

return allUsers
  .filter(guest => {
    const signIn = guest.signInActivity;
    if (!signIn || !signIn.lastSignInDateTime) {
      return new Date(guest.createdDateTime || '2000-01-01') < cutoffDate;
    }
    return new Date(signIn.lastSignInDateTime) < cutoffDate;
  })
  .map(guest => {
    const manager = guest.manager || null;
    const rawEmail = guest.mail || guest.userPrincipalName || '';
    return {
      json: {
        guestId:             guest.id,
        guestEmail:          rawEmail,
        guestEmailODataSafe: rawEmail.replace(/'/g, "''"),
        displayName:         guest.displayName || 'Unknown',
        lastSignIn:          (guest.signInActivity && guest.signInActivity.lastSignInDateTime)
                               ? guest.signInActivity.lastSignInDateTime
                               : 'Never',
        createdDateTime:     guest.createdDateTime,
        sponsorEmail:        manager ? (manager.mail || '') : '',
        sponsorName:         manager ? (manager.displayName || '') : ''
      }
    };
  });

